# 输入获取
n = int(input())
rans = [list(map(int, input().split(","))) for i in range(n)]


# 算法入口
def getResult(rans, n):
    rans.sort(key=lambda x: x[0])
    stack = [rans[0]]

    for i in range(1, n):
        ran = rans[i]

        while True:
            if len(stack) == 0:
                stack.append(ran)
                break

            s0, e0 = stack[-1]
            s1, e1 = ran

            if s1 <= s0:
                if e1 <= s0:
                    break
                elif e1 < e0:
                    break
                else:
                    stack.pop()
            elif s1 < e0:
                if e1 <= e0:
                    break
                else:
                    stack.append([e0, e1])
                    break
            else:
                stack.append(ran)
                break

    return len(stack)


# 算法调用
print(getResult(rans, n))
